const CACHE_VERSION = 'v3';

// Disable the service worker on localhost. In development a caching SW serves
// stale built chunks and fights Next.js HMR, causing infinite hard-reload loops.
const IS_DEV =
  self.location.hostname === 'localhost' || self.location.hostname === '127.0.0.1';
const STATIC_CACHE = `xcreatives-static-${CACHE_VERSION}`;
const PAGE_CACHE = `xcreatives-pages-${CACHE_VERSION}`;
const API_CACHE = `xcreatives-api-${CACHE_VERSION}`;
const IMAGE_CACHE = `xcreatives-images-${CACHE_VERSION}`;

const PRECACHE_PAGES = [
  '/',
  '/en',
  '/fr',
  '/offline',
  '/en/services',
  '/en/work',
  '/en/insights',
  '/en/contact',
];

const PRECACHE_ASSETS = [
  '/manifest.json',
  '/icon-192x192.png',
  '/icon-512x512.png',
];

// Install: precache critical pages and assets
self.addEventListener('install', (event) => {
  if (IS_DEV) {
    event.waitUntil(self.skipWaiting());
    return;
  }
  event.waitUntil(
    Promise.all([
      caches.open(PAGE_CACHE).then((cache) => cache.addAll(PRECACHE_PAGES)),
      caches.open(STATIC_CACHE).then((cache) => cache.addAll(PRECACHE_ASSETS)),
    ]).then(() => self.skipWaiting())
  );
});

// Activate: clean old caches
self.addEventListener('activate', (event) => {
  if (IS_DEV) {
    event.waitUntil(
      (async () => {
        const keys = await caches.keys();
        await Promise.all(keys.map((k) => caches.delete(k)));
        await self.registration.unregister();
        const clients = await self.clients.matchAll({ type: 'window' });
        clients.forEach((c) => c.navigate(c.url));
      })()
    );
    return;
  }
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames
          .filter((name) => name.startsWith('xcreatives-') && !name.includes(CACHE_VERSION))
          .map((name) => caches.delete(name))
      );
    }).then(() => self.clients.claim())
  );
});

// Helper: determine cache strategy
function getStrategy(request) {
  const url = new URL(request.url);
  const pathname = url.pathname;

  // API calls
  if (pathname.startsWith('/api/')) {
    return 'api';
  }

  // Static assets
  if (
    pathname.endsWith('.js') ||
    pathname.endsWith('.css') ||
    pathname.endsWith('.woff2') ||
    pathname.endsWith('.woff')
  ) {
    return 'static';
  }

  // Images
  if (
    pathname.endsWith('.png') ||
    pathname.endsWith('.jpg') ||
    pathname.endsWith('.jpeg') ||
    pathname.endsWith('.svg') ||
    pathname.endsWith('.webp') ||
    pathname.endsWith('.gif')
  ) {
    return 'image';
  }

  // HTML pages (navigation)
  if (request.mode === 'navigate' || request.destination === 'document') {
    return 'page';
  }

  return null;
}

// Stale-while-revalidate: return cached version immediately, then update cache
async function staleWhileRevalidate(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cached = await cache.match(request);

  const fetchPromise = fetch(request)
    .then((response) => {
      if (response.status === 200) {
        cache.put(request, response.clone());
      }
      return response;
    })
    .catch(() => cached);

  return cached || fetchPromise;
}

// Network-first with cache fallback
async function networkFirst(request, cacheName, fallbackUrl) {
  const cache = await caches.open(cacheName);

  try {
    const networkResponse = await fetch(request);
    if (networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  } catch (err) {
    const cached = await cache.match(request);
    if (cached) return cached;

    if (fallbackUrl) {
      const fallback = await cache.match(fallbackUrl);
      if (fallback) return fallback;
    }

    throw err;
  }
}

// Cache-first with network fallback
async function cacheFirst(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cached = await cache.match(request);
  if (cached) return cached;

  try {
    const networkResponse = await fetch(request);
    if (networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  } catch (err) {
    throw err;
  }
}

// Fetch handler
self.addEventListener('fetch', (event) => {
  if (IS_DEV) return;
  const { request } = event;

  // Skip non-GET requests (except for background sync)
  if (request.method !== 'GET') {
    return;
  }

  const strategy = getStrategy(request);
  if (!strategy) return;

  switch (strategy) {
    case 'page':
      event.respondWith(
        staleWhileRevalidate(request, PAGE_CACHE).catch(() =>
          caches.match('/offline')
        )
      );
      break;

    case 'static':
      event.respondWith(cacheFirst(request, STATIC_CACHE));
      break;

    case 'image':
      event.respondWith(
        cacheFirst(request, IMAGE_CACHE).catch(() => {
          // Return a 1x1 transparent pixel for missing images
          return new Response(
            new Uint8Array([0x47, 0x49, 0x46, 0x38, 0x39, 0x61, 0x01, 0x00, 0x01, 0x00, 0x00, 0x00, 0x00, 0x3b]),
            { headers: { 'Content-Type': 'image/gif' } }
          );
        })
      );
      break;

    case 'api':
      // Only cache safe API calls (GET requests to certain endpoints)
      event.respondWith(
        networkFirst(request, API_CACHE, null).catch((err) => {
          // Return a JSON error for failed API calls
          return new Response(
            JSON.stringify({ error: 'You are offline. This data is not cached.' }),
            { status: 503, headers: { 'Content-Type': 'application/json' } }
          );
        })
      );
      break;
  }
});

// Background sync for form submissions
self.addEventListener('sync', (event) => {
  if (event.tag === 'form-submissions') {
    event.waitUntil(processFormSubmissions());
  }
});

async function processFormSubmissions() {
  const db = await openSyncDB();
  const submissions = await db.getAll('formSubmissions');

  for (const submission of submissions) {
    try {
      const response = await fetch(submission.url, {
        method: submission.method,
        headers: submission.headers,
        body: JSON.stringify(submission.body),
      });

      if (response.ok) {
        await db.delete('formSubmissions', submission.id);
      }
    } catch (err) {
      // Will retry on next sync
    }
  }
}

// IndexedDB helper for background sync
function openSyncDB() {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('xcreatives-sync', 1);
    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = event.target.result;
      if (!db.objectStoreNames.contains('formSubmissions')) {
        db.createObjectStore('formSubmissions', { keyPath: 'id', autoIncrement: true });
      }
    };
  });
}

// Message handler for cache updates from client
self.addEventListener('message', (event) => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

"use client";

import { useCallback, useEffect, useState } from "react";
import { api } from "@/lib/api";
import { FileSignature, Send, CheckCircle, Clock, XCircle, Eye, Loader2, X, Download } from "lucide-react";

const statusColors: Record<string, string> = {
  draft: "text-white/50 bg-white/5",
  sent: "text-blue-400 bg-blue-400/10",
  viewed: "text-yellow-400 bg-yellow-400/10",
  signed: "text-green-400 bg-green-400/10",
  declined: "text-red-400 bg-red-400/10",
  expired: "text-white/30 bg-white/5",
};

const statusLabels: Record<string, string> = {
  draft: "Draft",
  sent: "Sent",
  viewed: "Viewed",
  signed: "Signed",
  declined: "Declined",
  expired: "Expired",
};

interface SignatureRequest {
  id: string;
  document_type: string;
  recipient_email: string;
  recipient_name: string;
  recipient_org: string;
  document_title: string;
  status: string;
  signing_url: string;
  signed_document_url: string;
  signed_at: string;
  created_at: string;
  expires_at: string;
}

interface SignatureRequestsResponse {
  requests?: SignatureRequest[];
}

export default function AdminSignaturesPage() {
  const [requests, setRequests] = useState<SignatureRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [sending, setSending] = useState<string | null>(null);
  const [viewing, setViewing] = useState<SignatureRequest | null>(null);

  const [form, setForm] = useState({
    document_type: "nda",
    recipient_email: "",
    recipient_name: "",
    recipient_org: "",
    document_title: "",
    document_body: "",
  });

  const fetchRequests = useCallback(async () => {
    try {
      const res = (await api.listSignatureRequests(
        filter || undefined,
      )) as SignatureRequestsResponse;
      setRequests(res.requests || []);
    } catch {
      // ignore
    } finally {
      setLoading(false);
    }
  }, [filter]);

  useEffect(() => {
    let active = true;
    void api
      .listSignatureRequests(filter || undefined)
      .then((res) => {
        if (!active) return;
        setRequests((res as SignatureRequestsResponse).requests || []);
      })
      .catch(() => {
        // ignore
      })
      .finally(() => {
        if (active) setLoading(false);
      });
    return () => {
      active = false;
    };
  }, [filter]);

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    try {
      await api.createSignatureRequest(form);
      setShowForm(false);
      setForm({ document_type: "nda", recipient_email: "", recipient_name: "", recipient_org: "", document_title: "", document_body: "" });
      await fetchRequests();
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : "Failed to create signature request");
    }
  }

  async function handleSend(id: string) {
    setSending(id);
    try {
      await api.sendSignatureRequest(id);
      await fetchRequests();
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : "Failed to send");
    } finally {
      setSending(null);
    }
  }

  if (loading) {
    return <div className="text-white/60">Loading signature requests...</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <FileSignature className="w-5 h-5 text-signal" />
          <h1 className="text-2xl font-bold">Signature Requests</h1>
        </div>
        <div className="flex items-center gap-3">
          <select
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
          >
            <option value="">All statuses</option>
            {Object.keys(statusLabels).map((s) => (
              <option key={s} value={s}>{statusLabels[s]}</option>
            ))}
          </select>
          <button
            onClick={() => setShowForm((s) => !s)}
            className="bg-signal text-white px-4 py-2 rounded text-sm font-medium hover:opacity-90 transition-opacity"
          >
            {showForm ? "Cancel" : "New Request"}
          </button>
        </div>
      </div>

      {showForm && (
        <form onSubmit={handleCreate} className="border border-white/10 rounded-lg p-6 bg-foundation space-y-4">
          <h2 className="font-semibold">Create Signature Request</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Document Type</label>
              <select
                value={form.document_type}
                onChange={(e) => setForm({ ...form, document_type: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              >
                <option value="nda">NDA</option>
                <option value="mou">MoU</option>
                <option value="sow">Statement of Work</option>
                <option value="amendment">Amendment</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Recipient Email *</label>
              <input
                type="email"
                required
                value={form.recipient_email}
                onChange={(e) => setForm({ ...form, recipient_email: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Recipient Name</label>
              <input
                value={form.recipient_name}
                onChange={(e) => setForm({ ...form, recipient_name: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Organisation</label>
              <input
                value={form.recipient_org}
                onChange={(e) => setForm({ ...form, recipient_org: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Document Title *</label>
            <input
              required
              value={form.document_title}
              onChange={(e) => setForm({ ...form, document_title: e.target.value })}
              className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
            />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Document Body *</label>
            <textarea
              required
              value={form.document_body}
              onChange={(e) => setForm({ ...form, document_body: e.target.value })}
              rows={6}
              className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              placeholder="Paste the document text here..."
            />
          </div>
          <button
            type="submit"
            className="bg-signal text-white px-5 py-2.5 rounded text-sm font-medium hover:opacity-90 transition-opacity"
          >
            Create Draft
          </button>
        </form>
      )}

      {requests.length === 0 ? (
        <div className="border border-white/10 rounded-lg p-8 text-center text-white/40">
          <Clock className="w-8 h-8 mx-auto mb-3 opacity-50" />
          <p>No signature requests found.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {requests.map((req) => (
            <div key={req.id} className="border border-white/10 rounded-lg bg-foundation p-5">
              <div className="flex items-center justify-between">
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`px-2 py-0.5 rounded text-xs font-medium ${statusColors[req.status] || ""}`}>
                      {statusLabels[req.status] || req.status}
                    </span>
                    <span className="text-xs text-white/30 uppercase">{req.document_type}</span>
                  </div>
                  <p className="font-medium">{req.document_title}</p>
                  <p className="text-sm text-white/50">
                    {req.recipient_name || req.recipient_email} · {req.recipient_org || "No org"}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  {req.status === "draft" && (
                    <button
                      onClick={() => handleSend(req.id)}
                      disabled={sending === req.id}
                      className="flex items-center gap-1 bg-signal text-white px-3 py-1.5 rounded text-xs font-medium hover:opacity-90 transition-opacity disabled:opacity-50"
                    >
                      {sending === req.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Send className="w-3 h-3" />}
                      Send
                    </button>
                  )}
                  {req.status === "sent" && req.signing_url && (
                    <a
                      href={req.signing_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-1 border border-white/10 text-white/60 px-3 py-1.5 rounded text-xs hover:border-signal hover:text-signal transition-colors"
                    >
                      <Eye className="w-3 h-3" /> View
                    </a>
                  )}
                  {req.status === "signed" && (
                    <button
                      onClick={() => setViewing(req)}
                      className="flex items-center gap-1 bg-green-500/10 text-green-400 px-3 py-1.5 rounded text-xs font-medium hover:bg-green-500/20 transition-colors"
                    >
                      <CheckCircle className="w-3 h-3" /> View Signature
                    </button>
                  )}
                  {req.status === "declined" && (
                    <span className="flex items-center gap-1 text-red-400 text-xs">
                      <XCircle className="w-3 h-3" /> Declined
                    </span>
                  )}
                </div>
              </div>
              <p className="mt-3 text-xs text-white/30">
                Created {new Date(req.created_at).toLocaleDateString()}
                {req.expires_at && ` · Expires ${new Date(req.expires_at).toLocaleDateString()}`}
              </p>
            </div>
          ))}
        </div>
      )}

      {/* View Signature Modal */}
      {viewing && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gravity border border-white/10 rounded-lg max-w-lg w-full p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold">Signed Document</h3>
              <button onClick={() => setViewing(null)} className="text-white/40 hover:text-white">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="space-y-4">
              <div className="flex items-center gap-2 text-sm">
                <CheckCircle className="w-4 h-4 text-green-400" />
                <span>Signed by <strong>{viewing.recipient_name || viewing.recipient_email}</strong></span>
              </div>
              {viewing.signed_at && (
                <p className="text-xs text-white/50">
                  {new Date(viewing.signed_at).toLocaleString()}
                </p>
              )}
              {viewing.signed_document_url?.startsWith("data:") ? (
                <img
                  src={viewing.signed_document_url}
                  alt="Signature"
                  className="w-full bg-white rounded border border-white/10"
                />
              ) : (
                <div className="border border-white/10 rounded p-4 bg-white/5">
                  <p className="text-sm text-white/70 font-mono">{viewing.signed_document_url}</p>
                </div>
              )}
              <a
                href={viewing.signed_document_url}
                download={`${viewing.document_title}_signed.png`}
                className="flex items-center justify-center gap-2 w-full bg-white/5 text-white px-4 py-2.5 rounded text-sm font-medium hover:bg-white/10 transition-colors"
              >
                <Download className="w-4 h-4" />
                Download Signature
              </a>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { api } from "@/lib/api";
import { FileUpload } from "@/components/FileUpload";
import { Palette, CheckCircle } from "lucide-react";

export default function AdminThemesPage() {
  const [engagementId, setEngagementId] = useState("");
  const [clientName, setClientName] = useState("");
  const [primaryColor, setPrimaryColor] = useState("#0066CC");
  const [logoUrl, setLogoUrl] = useState("");
  const [saved, setSaved] = useState(false);
  const [saving, setSaving] = useState(false);

  async function handleSave(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    try {
      await api.upsertClientTheme({
        engagement_id: engagementId,
        client_name: clientName,
        primary_color: primaryColor,
        logo_url: logoUrl || undefined,
      });
      setSaved(true);
      setTimeout(() => setSaved(false), 3000);
    } catch {
      alert("Failed to save theme");
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="space-y-8 max-w-2xl">
      <div className="flex items-center gap-2">
        <Palette className="w-5 h-5 text-signal" />
        <h1 className="text-2xl font-bold">Client Theme Management</h1>
      </div>

      <form onSubmit={handleSave} className="space-y-5 border border-white/10 rounded-lg p-6 bg-foundation">
        <div>
          <label className="block text-sm font-medium mb-1">Engagement ID *</label>
          <input
            value={engagementId}
            onChange={(e) => setEngagementId(e.target.value)}
            placeholder="uuid"
            required
            className="w-full bg-gravity border border-white/10 rounded px-4 py-2 text-sm text-white focus:outline-none focus:border-signal"
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Client Name *</label>
          <input
            value={clientName}
            onChange={(e) => setClientName(e.target.value)}
            placeholder="Client Organisation"
            required
            className="w-full bg-gravity border border-white/10 rounded px-4 py-2 text-sm text-white focus:outline-none focus:border-signal"
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Primary Color</label>
          <div className="flex items-center gap-3">
            <input
              type="color"
              value={primaryColor}
              onChange={(e) => setPrimaryColor(e.target.value)}
              className="w-10 h-10 rounded border-none bg-transparent cursor-pointer"
            />
            <input
              value={primaryColor}
              onChange={(e) => setPrimaryColor(e.target.value)}
              className="flex-1 bg-gravity border border-white/10 rounded px-4 py-2 text-sm text-white focus:outline-none focus:border-signal"
            />
          </div>
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Logo</label>
          <FileUpload
            value={logoUrl}
            onChange={(url) => setLogoUrl(url)}
            folder="logos"
            accept="image/*"
            label="Upload logo (PNG / SVG)"
          />
        </div>

        <div className="flex items-center gap-3">
          <button
            type="submit"
            disabled={saving}
            className="bg-signal text-white px-5 py-2.5 rounded text-sm font-medium hover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {saving ? "Saving..." : "Save Theme"}
          </button>
          {saved && (
            <span className="flex items-center gap-1 text-sm text-green-400">
              <CheckCircle className="w-4 h-4" /> Saved
            </span>
          )}
        </div>
      </form>

      <div className="border border-white/10 rounded-lg p-6 bg-foundation">
        <h2 className="font-semibold mb-3">Preview</h2>
        <div
          className="p-4 rounded border border-white/10"
          style={{ borderLeftWidth: "4px", borderLeftColor: primaryColor }}
        >
          {logoUrl ? (
            <img src={logoUrl} alt={clientName} className="h-8 w-auto mb-2" />
          ) : (
            <p className="font-bold" style={{ color: primaryColor }}>
              {clientName || "Client Portal"}
            </p>
          )}
          <p className="text-xs text-white/40 mt-1">Primary: {primaryColor}</p>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { AlertTriangle, Plus, Pencil, Trash2, X, Save } from "lucide-react";
import ThreadedComments from "@/components/portal/ThreadedComments";

interface Risk {
  ID: string;
  Title: string;
  Description: string;
  MitigationPlan: string;
  ResidualRating: string;
  Severity: string;
  EscalationStatus: string;
  Status: string;
}

interface RisksResponse {
  risks?: Risk[];
}

const severityColor = (s: string) => {
  if (s === "critical") return "text-red-500";
  if (s === "high") return "text-red-400";
  if (s === "medium") return "text-yellow-400";
  return "text-green-400";
};

const statusConfig: Record<string, { color: string; label: string }> = {
  open: { color: "text-red-400 bg-red-400/10 border-red-400/30", label: "Open" },
  mitigated: { color: "text-amber-400 bg-amber-400/10 border-amber-400/30", label: "Mitigated" },
  accepted: { color: "text-yellow-400 bg-yellow-400/10 border-yellow-400/30", label: "Accepted" },
  closed: { color: "text-green-400 bg-green-400/10 border-green-400/30", label: "Closed" },
};

export default function RisksPage() {
  const { id } = useParams();
  const [risks, setRisks] = useState<Risk[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState({ title: "", description: "", mitigation_plan: "", residual_rating: "", severity: "medium", escalation_status: "none", status: "open", linked_decision_id: null as string | null });
  const [submitting, setSubmitting] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const load = async () => {
    if (!id) return;
    setLoading(true);
    try {
      const d = (await api.listRisks(id as string)) as RisksResponse;
      setRisks(d.risks || []);
      setError("");
    } catch {
      setError("Failed to load risks");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    let active = true;
    Promise.resolve().then(() => {
      if (active) void load();
    });
    return () => {
      active = false;
    };
  }, [id]);

  const resetForm = () => {
    setForm({ title: "", description: "", mitigation_plan: "", residual_rating: "", severity: "medium", escalation_status: "none", status: "open", linked_decision_id: null });
    setShowForm(false);
    setEditingId(null);
  };

  const handleCreate = async () => {
    if (!id || !form.title.trim()) return;
    setSubmitting(true);
    try {
      await api.createRisk(id as string, { ...form, title: form.title.trim() });
      resetForm();
      await load();
    } catch {
      setError("Failed to create risk");
    } finally {
      setSubmitting(false);
    }
  };

  const handleUpdate = async () => {
    if (!id || !editingId || !form.title.trim()) return;
    setSubmitting(true);
    try {
      await api.updateRisk(id as string, editingId, { ...form, title: form.title.trim() });
      resetForm();
      await load();
    } catch {
      setError("Failed to update risk");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (rid: string) => {
    if (!id) return;
    setDeleteId(rid);
    try {
      await api.deleteRisk(id as string, rid);
      await load();
    } catch {
      setError("Failed to delete risk");
    } finally {
      setDeleteId(null);
    }
  };

  const startEdit = (r: Risk) => {
    setForm({ title: r.Title, description: r.Description, mitigation_plan: r.MitigationPlan, residual_rating: r.ResidualRating, severity: r.Severity, escalation_status: r.EscalationStatus, status: r.Status, linked_decision_id: null });
    setEditingId(r.ID);
    setShowForm(true);
  };

  if (error && !risks.length) return <div className="text-white/60">{error}</div>;
  if (loading) return <div className="text-white/60">Loading...</div>;

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold">Risk Register</h2>
        <button onClick={() => { resetForm(); setShowForm(true); }} className="flex items-center gap-1 px-3 py-1.5 text-sm bg-signal text-black rounded-md hover:bg-signal/90 transition">
          <Plus className="w-4 h-4" /> Add
        </button>
      </div>

      {showForm && (
        <div className="border border-white/10 rounded-lg p-4 mb-6 bg-white/[0.03]">
          <div className="flex items-center justify-between mb-3">
            <h3 className="text-sm font-medium">{editingId ? "Edit Risk" : "New Risk"}</h3>
            <button onClick={resetForm} className="text-white/40 hover:text-white/70"><X className="w-4 h-4" /></button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
            <div className="md:col-span-3">
              <label className="text-xs text-white/50 mb-1 block">Title</label>
              <input value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal" placeholder="Risk title" />
            </div>
            <div>
              <label className="text-xs text-white/50 mb-1 block">Severity</label>
              <select value={form.severity} onChange={(e) => setForm({ ...form, severity: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal">
                <option value="low">Low</option>
                <option value="medium">Medium</option>
                <option value="high">High</option>
                <option value="critical">Critical</option>
              </select>
            </div>
            <div>
              <label className="text-xs text-white/50 mb-1 block">Status</label>
              <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal">
                <option value="open">Open</option>
                <option value="mitigated">Mitigated</option>
                <option value="accepted">Accepted</option>
                <option value="closed">Closed</option>
              </select>
            </div>
            <div>
              <label className="text-xs text-white/50 mb-1 block">Escalation</label>
              <select value={form.escalation_status} onChange={(e) => setForm({ ...form, escalation_status: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal">
                <option value="none">None</option>
                <option value="watch">Watch</option>
                <option value="escalated">Escalated</option>
                <option value="resolved">Resolved</option>
              </select>
            </div>
            <div className="md:col-span-3">
              <label className="text-xs text-white/50 mb-1 block">Description</label>
              <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal" rows={2} placeholder="Risk description" />
            </div>
            <div className="md:col-span-3">
              <label className="text-xs text-white/50 mb-1 block">Mitigation Plan</label>
              <textarea value={form.mitigation_plan} onChange={(e) => setForm({ ...form, mitigation_plan: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal" rows={2} placeholder="How will this be mitigated?" />
            </div>
            <div className="md:col-span-3">
              <label className="text-xs text-white/50 mb-1 block">Residual Rating</label>
              <input value={form.residual_rating} onChange={(e) => setForm({ ...form, residual_rating: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-signal" placeholder="e.g. medium, low" />
            </div>
          </div>
          <div className="flex justify-end gap-2 mt-3">
            <button onClick={resetForm} className="px-3 py-1.5 text-sm border border-white/10 rounded-md hover:bg-white/5">Cancel</button>
            <button onClick={editingId ? handleUpdate : handleCreate} disabled={submitting || !form.title.trim()} className="flex items-center gap-1 px-3 py-1.5 text-sm bg-signal text-black rounded-md hover:bg-signal/90 disabled:opacity-50">
              <Save className="w-4 h-4" /> {submitting ? "Saving..." : (editingId ? "Update" : "Create")}
            </button>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {risks.map((r) => {
          const cfg = statusConfig[r.Status] || statusConfig.open;
          return (
            <div key={r.ID} className="border border-white/10 rounded p-5 hover:border-signal/50 transition-colors group">
              <div className="flex items-start gap-3">
                <AlertTriangle className={`w-5 h-5 shrink-0 mt-0.5 ${severityColor(r.Severity)}`} />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-3 flex-wrap">
                    <h3 className="font-medium">{r.Title}</h3>
                    <span className={`text-xs font-medium uppercase ${severityColor(r.Severity)}`}>{r.Severity}</span>
                    <span className={`text-xs px-2 py-0.5 rounded-full border ${cfg.color}`}>{cfg.label}</span>
                  </div>
                  <p className="text-sm text-white/50 mt-1">{r.Description}</p>
                  {r.MitigationPlan && (
                    <div className="mt-3 p-3 bg-white/5 rounded text-sm">
                      <p className="text-white/40 text-xs uppercase tracking-wider mb-1">Mitigation</p>
                      <p className="text-white/70">{r.MitigationPlan}</p>
                    </div>
                  )}
                  <div className="flex gap-3 mt-3 text-xs text-white/40">
                    {r.ResidualRating && <span>Residual: {r.ResidualRating}</span>}
                    {r.EscalationStatus !== "none" && <span>Escalation: {r.EscalationStatus}</span>}
                  </div>
                </div>
                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => startEdit(r)} className="p-1.5 text-white/40 hover:text-signal hover:bg-white/5 rounded" title="Edit"><Pencil className="w-4 h-4" /></button>
                  <button onClick={() => handleDelete(r.ID)} disabled={deleteId === r.ID} className="p-1.5 text-white/40 hover:text-red-400 hover:bg-white/5 rounded" title="Delete"><Trash2 className="w-4 h-4" /></button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      <ThreadedComments engagementID={id as string} parentType="risks" parentID={id as string} />
    </div>
  );
}

"use client";

import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Mail, CheckCircle, Clock, Plus, X, Loader2, Trash2 } from "lucide-react";
import type { TeamMembersResponse } from "@/lib/types";

interface TeamMember {
  ID: string;
  Name: string;
  Role: string;
  Email: string;
  AvailabilityStatus: string;
  IsXCreativs: boolean;
}

export default function TeamPage() {
  const { id } = useParams();
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [removing, setRemoving] = useState<string | null>(null);

  const [form, setForm] = useState({
    name: "",
    role: "",
    email: "",
    availability_status: "available",
    is_xcreativs: false,
  });

  async function fetchMembers() {
    try {
      const res = (await api.listTeamMembers(id as string)) as TeamMembersResponse;
      setMembers((res.team_members as TeamMember[]) || []);
    } catch {
      setError("Failed to load data");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (!id) return;
    void (async () => {
      await fetchMembers();
    })();
  }, [id]);

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    try {
      await api.createTeamMember(id as string, form);
      setShowForm(false);
      setForm({ name: "", role: "", email: "", availability_status: "available", is_xcreativs: false });
      await fetchMembers();
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : "Failed to add team member");
    } finally {
      setSaving(false);
    }
  }

  async function handleRemove(memberID: string) {
    if (!confirm("Remove this team member?")) return;
    setRemoving(memberID);
    try {
      await api.removeTeamMember(id as string, memberID);
      await fetchMembers();
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : "Failed to remove");
    } finally {
      setRemoving(null);
    }
  }

  if (error) return <div className="text-white/60">{error}</div>;
  if (loading) return <div className="text-white/60">Loading...</div>;

  const xcreativs = members.filter((m) => m.IsXCreativs);
  const client = members.filter((m) => !m.IsXCreativs);

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold">Team Directory</h2>
        <button
          onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-1 bg-signal text-black px-3 py-1.5 rounded text-xs font-medium hover:opacity-90 transition-opacity"
        >
          <Plus className="w-3.5 h-3.5" />
          Add Member
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleCreate} className="border border-white/10 rounded-lg bg-foundation p-5 space-y-4 mb-6">
          <div className="flex items-center justify-between">
            <h3 className="font-medium text-sm">Add Team Member</h3>
            <button type="button" onClick={() => setShowForm(false)} className="text-white/40 hover:text-white">
              <X className="w-4 h-4" />
            </button>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-white/50 mb-1">Name *</label>
              <input
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
                placeholder="Jane Doe"
                required
              />
            </div>
            <div>
              <label className="block text-xs text-white/50 mb-1">Role *</label>
              <input
                value={form.role}
                onChange={(e) => setForm({ ...form, role: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
                placeholder="Product Lead"
                required
              />
            </div>
            <div>
              <label className="block text-xs text-white/50 mb-1">Email</label>
              <input
                type="email"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
                placeholder="jane@example.com"
              />
            </div>
            <div>
              <label className="block text-xs text-white/50 mb-1">Availability</label>
              <select
                value={form.availability_status}
                onChange={(e) => setForm({ ...form, availability_status: e.target.value })}
                className="w-full bg-gravity border border-white/10 rounded px-3 py-2 text-sm text-white"
              >
                <option value="available">Available</option>
                <option value="busy">Busy</option>
                <option value="away">Away</option>
                <option value="offline">Offline</option>
              </select>
            </div>
          </div>
          <label className="flex items-center gap-2 text-sm text-white/70">
            <input
              type="checkbox"
              checked={form.is_xcreativs}
              onChange={(e) => setForm({ ...form, is_xcreativs: e.target.checked })}
              className="rounded border-white/20"
            />
            XCreativs team member
          </label>
          <button
            type="submit"
            disabled={saving}
            className="flex items-center gap-1 bg-signal text-black px-4 py-2 rounded text-sm font-medium hover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
            Add Member
          </button>
        </form>
      )}

      {xcreativs.length > 0 && (
        <div className="mb-8">
          <h3 className="text-xs font-medium uppercase tracking-wider text-signal mb-3">XCreativs</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {xcreativs.map((m) => (
              <MemberCard key={m.ID} member={m} onRemove={handleRemove} removing={removing === m.ID} />
            ))}
          </div>
        </div>
      )}

      {client.length > 0 && (
        <div>
          <h3 className="text-xs font-medium uppercase tracking-wider text-white/40 mb-3">Client</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {client.map((m) => (
              <MemberCard key={m.ID} member={m} onRemove={handleRemove} removing={removing === m.ID} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function MemberCard({ member, onRemove, removing }: { member: TeamMember; onRemove: (id: string) => void; removing: boolean }) {
  const available = member.AvailabilityStatus === "available";
  return (
    <div className="flex items-start gap-3 border border-white/10 rounded-lg p-4 group">
      <div className="w-10 h-10 rounded-full bg-signal/20 flex items-center justify-center text-signal font-medium text-sm shrink-0">
        {member.Name.split(" ").map((n) => n[0]).join("").slice(0, 2)}
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-medium truncate">{member.Name}</p>
        <p className="text-sm text-white/50">{member.Role}</p>
        {member.Email && (
          <a href={`mailto:${member.Email}`} className="text-xs text-signal hover:underline flex items-center gap-1 mt-1">
            <Mail className="w-3 h-3" />
            {member.Email}
          </a>
        )}
      </div>
      <div className="flex flex-col items-end gap-2">
        <button
          onClick={() => onRemove(member.ID)}
          disabled={removing}
          className="opacity-0 group-hover:opacity-100 p-1.5 text-white/30 hover:text-red-400 transition-all disabled:opacity-50"
          title="Remove"
        >
          {removing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Trash2 className="w-3.5 h-3.5" />}
        </button>
        <div className={`flex items-center gap-1 text-xs ${available ? "text-green-400" : "text-white/30"}`}>
          {available ? <CheckCircle className="w-3 h-3" /> : <Clock className="w-3 h-3" />}
          <span className="capitalize">{member.AvailabilityStatus}</span>
        </div>
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { usePathname, useParams, useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import type { AuthUser } from "@/lib/types";
import {
  LayoutDashboard,
  LogOut,
  Briefcase,
  Shield,
  Settings,
  FileText,
  Handshake,
  Key,
  ClipboardList,
  Sun,
  Moon,
  BarChart3,
  Mail,
  Palette,
  FileSignature,
  Calendar,
  LayoutTemplate,
  Webhook,
  Bell,
} from "lucide-react";
import ChatWidget from "@/components/concierge/ChatWidget";
import ThemeProvider from "@/components/ThemeProvider";
import { useTheme } from "@/components/ThemeProvider";
import CurrencyProvider from "@/components/CurrencyProvider";
import { useCurrency, CurrencyCode } from "@/components/CurrencyProvider";
import NotificationBell from "@/components/NotificationBell";
import ClientThemeProvider, { useClientTheme } from "@/components/ClientThemeProvider";

export default function PortalLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <ClientThemeProvider>
      <PortalLayoutInner>{children}</PortalLayoutInner>
    </ClientThemeProvider>
  );
}

function PortalLayoutInner({
  children,
}: {
  children: React.ReactNode;
}) {
  const pathname = usePathname();
  const params = useParams();
  const router = useRouter();
  const locale = (params?.locale as string) || "en";
  const storedUser =
    typeof window !== "undefined" ? localStorage.getItem("user") : null;
  const [user, setUser] = useState<AuthUser | null>(() =>
    storedUser ? (JSON.parse(storedUser) as AuthUser) : null
  );
  const [authChecked, setAuthChecked] = useState(() => Boolean(storedUser));
  const { theme: clientTheme, setEngagementId } = useClientTheme();

  useEffect(() => {
    const token = localStorage.getItem("access_token");
    if (!token) {
      router.push(`/${locale}/login`);
      return;
    }

    if (!localStorage.getItem("user")) {
      api.me()
        .then((u) => {
          setUser(u as AuthUser);
          localStorage.setItem("user", JSON.stringify(u));
          setAuthChecked(true);
        })
        .catch(() => {
          router.push(`/${locale}/login`);
        });
    }
  }, [router, locale]);

  useEffect(() => {
    const match = pathname.match(/\/engagements\/([^\/]+)/);
    setEngagementId(match ? match[1] : null);
  }, [pathname, setEngagementId]);

  const { theme, toggleTheme } = useTheme();
  const { currency, setCurrency } = useCurrency();

  const handleLogout = async () => {
    try {
      await api.logout();
    } catch {
      // ignore
    }
    window.location.href = `/${locale}`;
  };

  if (!authChecked) {
    return (
      <div className="min-h-screen bg-gravity text-foundation flex items-center justify-center">
        <div className="text-white/50">Loading...</div>
      </div>
    );
  }

  return (
    <ThemeProvider defaultTheme="dark">
      <CurrencyProvider>
      <div className="min-h-screen bg-gravity text-foundation flex">
        {/* Sidebar */}
        <aside className="w-64 border-r border-white/10 flex flex-col">
        <div className="p-6">
          {clientTheme?.logo_url ? (
            <Link href={`/${locale}/portal`} className="block">
              <img src={clientTheme.logo_url} alt={clientTheme.client_name} className="h-8 w-auto" />
            </Link>
          ) : (
            <Link href={`/${locale}/portal`} className="text-xl font-bold tracking-tight" style={{ color: clientTheme?.primary_color || undefined }}>
              {clientTheme?.client_name || "XCreativs Portal"}
            </Link>
          )}
        </div>

        <nav className="flex-1 px-4 space-y-1">
          <SidebarLink
            href={`/${locale}/portal`}
            icon={<LayoutDashboard className="w-4 h-4" />}
            label="Overview"
            active={pathname === `/${locale}/portal`}
          />
          <SidebarLink
            href={`/${locale}/portal/engagements`}
            icon={<Briefcase className="w-4 h-4" />}
            label="Engagements"
            active={pathname.startsWith(`/${locale}/portal/engagements`)}
          />
          <SidebarLink
            href={`/${locale}/portal/notifications`}
            icon={<Bell className="w-4 h-4" />}
            label="Notifications"
            active={pathname === `/${locale}/portal/notifications`}
          />
          <SidebarLink
            href={`/${locale}/portal/partner`}
            icon={<Handshake className="w-4 h-4" />}
            label="Partner"
            active={pathname.startsWith(`/${locale}/portal/partner`)}
          />
          <SidebarLink
            href={`/${locale}/portal/mfa`}
            icon={<Shield className="w-4 h-4" />}
            label="Security"
            active={pathname === `/${locale}/portal/mfa`}
          />
          <SidebarLink
            href={`/${locale}/portal/settings`}
            icon={<Settings className="w-4 h-4" />}
            label="Settings"
            active={pathname === `/${locale}/portal/settings`}
          />
          <SidebarLink
            href={`/${locale}/portal/api-keys`}
            icon={<Key className="w-4 h-4" />}
            label="API Keys"
            active={pathname === `/${locale}/portal/api-keys`}
          />
          <SidebarLink
            href={`/${locale}/portal/applications`}
            icon={<FileText className="w-4 h-4" />}
            label="My Applications"
            active={pathname === `/${locale}/portal/applications`}
          />
